/**
 * Clean reimplementation of the obfuscated physics simulation.
 *
 * What it does:
 * - Simulates a small network of nodes.
 * - Every node attracts every other node with inverse-square force.
 * - Some node pairs are linked by springs.
 * - A weak centering force pulls everything toward the canvas center.
 * - Velocities are damped each step.
 * - Decorative particles ("streams") spawn from random nodes and drift/fade by age.
 * - A camera smoothly interpolates toward a target camera.
 */

const TAU = Math.PI * 2;
const GOLDEN_RATIO = 1.618;
const ROOT_HALF = 0.707;

const settings = {
  attraction: 4000,
  springCoefficient: 0.004,
  damping: 0.92,
  centeringForce: 0.0003,
  streamLimit: 40,
  streamDecay: 0.04,
  cameraLerp: 0.06,
};

const nodes = [
  { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 },
];

const springs = [
  { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
  { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
  { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 },
];

const camera = {
  x: 400,
  y: 300,
  zoom: 1,
};

const targetCamera = {
  x: 400,
  y: 300,
  zoom: 1,
};

const particles = [];
let tick = 0;

function findNodeById(id) {
  return nodes.find(node => node.id === id) || null;
}

function updateNodePhysics() {
  // Pairwise attraction between all nodes.
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const a = nodes[i];
      const b = nodes[j];

      const dx = a.x - b.x;
      const dy = a.y - b.y;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;

      const force = settings.attraction / (distance * distance);
      const fx = (dx / distance) * force;
      const fy = (dy / distance) * force;

      a.vx += fx;
      a.vy += fy;
      b.vx -= fx;
      b.vy -= fy;
    }
  }

  // Spring constraints.
  for (const spring of springs) {
    const a = findNodeById(spring.a);
    const b = findNodeById(spring.b);
    if (!a || !b) continue;

    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const distance = Math.sqrt(dx * dx + dy * dy) || 1;

    const extension = distance - spring.rest;
    const force = (spring.k ?? settings.springCoefficient) * extension;

    const fx = (dx / distance) * force;
    const fy = (dy / distance) * force;

    a.vx += fx;
    a.vy += fy;
    b.vx -= fx;
    b.vy -= fy;
  }

  // Centering force, integration, damping.
  for (const node of nodes) {
    node.vx += (400 - node.x) * settings.centeringForce;
    node.vy += (300 - node.y) * settings.centeringForce;

    node.x += node.vx;
    node.y += node.vy;

    node.vx *= settings.damping;
    node.vy *= settings.damping;
  }
}

function spawnParticle() {
  if (particles.length >= settings.streamLimit) return;

  const source = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * ROOT_HALF;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * ROOT_HALF,
  });
}

function updateParticles() {
  const particleDamping = 1 - settings.streamDecay * 0.125;

  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];

    p.x += p.vx;
    p.y += p.vy;

    p.vx *= particleDamping;
    p.vy *= particleDamping;

    p.age += 1;

    if (p.age > p.maxAge) {
      particles.splice(i, 1);
    }
  }
}

function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * settings.cameraLerp;
  camera.y += (targetCamera.y - camera.y) * settings.cameraLerp;
  camera.zoom += (targetCamera.zoom - camera.zoom) * settings.cameraLerp;
}

function stepSimulation() {
  updateNodePhysics();
  updateParticles();
  updateCamera();

  if (tick % 3 === 0) {
    spawnParticle();
  }

  tick++;
}

setInterval(stepSimulation, 10);
```

A few notes about behavior reproduced from the original:

- The “attraction” force is actually applied symmetrically between every pair of nodes.
- The spring force uses `distance - restLength`, so it pulls together when stretched and pushes apart when compressed.
- The center point is fixed at `(400, 300)`.
- Particles are purely kinematic and not affected by node forces.
- The camera only interpolates; in this code its target stays fixed unless you change `targetCamera`.

